bootstrap.ps1:
$ErrorActionPreference = 'Stop';
function Invoke-Step { param([string]$Label,[ScriptBlock]$Action) Write-Host "[STEP] $Label" -ForegroundColor Cyan; & $Action }
function Write-File { param([string]$Path,[string]$Content,[switch]$NoNewLine=$false) $dir = Split-Path -Parent $Path; if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null } ; if ($env:DRY_RUN -eq 'true') { Write-Host "DRY-RUN: write -> $Path" } else { if ($NoNewLine) { Set-Content -LiteralPath $Path -Value $Content -Encoding UTF8 -NoNewline } else { Set-Content -LiteralPath $Path -Value $Content -Encoding UTF8 } } }
function Append-Lines-IfMissing { param([string]$Path,[string[]]$Lines) if (-not (Test-Path $Path)) { if ($env:DRY_RUN -eq 'true') { Write-Host "DRY-RUN: create $Path" } else { New-Item -ItemType File -Force -Path $Path | Out-Null } } $existing = Get-Content -LiteralPath $Path -ErrorAction SilentlyContinue; foreach ($L in $Lines) { if (-not ($existing -contains $L)) { if ($env:DRY_RUN -eq 'true') { Write-Host "DRY-RUN: append '$L' -> $Path" } else { Add-Content -LiteralPath $Path -Value $L } } } }

$DRY = [bool]::Parse($env:DRY_RUN ?? 'true');
$DOMAIN = $env:SITE_DOMAIN; if (-not $DOMAIN) { $DOMAIN = 'https://disaster-recovery-seven.vercel.app' }
$STAMP = Get-Date -Format 'yyyyMMdd-HHmmss';
$BUNDLE = "${env:CD}\${env:bundlePrefix}"

# 0) Sanity checks
Invoke-Step 'Preflight: Node & npm present' { node -v; npm -v }
Invoke-Step 'Preflight: Git status' { try { git status -s } catch { Write-Host 'Git not available (ok for zip-only bundle)' -ForegroundColor Yellow } }

# 1) Ensure required folders exist
Invoke-Step 'Ensure required folders' { if (-not (Test-Path 'public')) { if ($DRY) { Write-Host 'DRY-RUN: mkdir public' } else { New-Item -ItemType Directory public | Out-Null } } if (-not (Test-Path '_archive')) { if ($DRY) { Write-Host 'DRY-RUN: mkdir _archive' } else { New-Item -ItemType Directory _archive | Out-Null } } }

# 2) Robots.txt (disallow CRM/admin/api; point to sitemap)
Invoke-Step 'Generate robots.txt' {
  $disallows = @('/crm','/admin','/api'); if ($env:DISALLOW_PATHS) { $disallows = $env:DISALLOW_PATHS.Split(';') }
  $rb = "User-agent: *`n" + ($disallows | ForEach-Object { "Disallow: $_`n" }) + "Allow: /`nSitemap: $DOMAIN/sitemap.xml`n";
  Write-File -Path 'public/robots.txt' -Content $rb
}

# 3) Build prep: minimal 404 & 500 (if missing). Non-invasive.
Invoke-Step 'Ensure basic public error pages (fallbacks)' {
  if (-not (Test-Path 'public/404.html')) { Write-File 'public/404.html' '<!doctype html><meta charset="utf-8"><title>Not Found</title><h1>404 - Not Found</h1><p>Sorry, we could not find that page.</p>' }
  if (-not (Test-Path 'public/500.html')) { Write-File 'public/500.html' '<!doctype html><meta charset="utf-8"><title>Error</title><h1>500 - Server Error</h1><p>Please try again later.</p>' }
}

# 4) Env file scaffolding (non-secret example)
Invoke-Step 'Ensure .env.production.example exists' {
  if (-not (Test-Path '.env.production.example')) {
    $envExample = "# Production env example (copy to .env.production and fill real secrets)\nNEXT_PUBLIC_SITE_URL=$DOMAIN\n# DATABASE_URL=\n# NEXTAUTH_SECRET=\n# SENTRY_DSN=\n# MAINTENANCE_MODE=false\n"; Write-File '.env.production.example' $envExample
  }
}

# 5) Install & build (gracefully run lint/type-check if scripts exist)
Invoke-Step 'npm ci (clean install)' { if ($DRY) { Write-Host 'DRY-RUN: npm ci' } else { npm ci } }
Invoke-Step 'Optional: lint & type-check' {
  if (-not $DRY) {
    $pj = Get-Content package.json -Raw | ConvertFrom-Json
    if ($pj.scripts.'lint') { try { npm run lint } catch { Write-Host 'lint failed (non-blocking)' -ForegroundColor Yellow } }
    if ($pj.scripts.'type-check') { try { npm run type-check } catch { Write-Host 'type-check failed (non-blocking)' -ForegroundColor Yellow } }
  } else { Write-Host 'DRY-RUN: npm run lint / type-check (if present)' }
}
Invoke-Step 'Next.js production build' { if ($DRY) { Write-Host 'DRY-RUN: npm run build' } else { npm run build } }

# 6) Generate sitemap.xml from built static routes (App Router)
Invoke-Step 'Generate sitemap.xml' {
  $serverApp = '.next/server/app'; $routes = @('/');
  if (Test-Path $serverApp) {
    $pages = Get-ChildItem -Path $serverApp -Recurse -Include page.js,page.mjs,page.cjs,page.ts,page.tsx -ErrorAction SilentlyContinue;
    foreach ($p in $pages) {
      $dir = Split-Path -Parent $p.FullName
      $rel = ($dir.Substring((Resolve-Path $serverApp).Path.Length)).TrimStart('\\','/')
      $segments = $rel -split '[\\]|[/]'
      $segments = $segments | Where-Object { $_ -and ($_ -notmatch '^\[.*\]$') -and ($_ -notmatch '^\(.*\)$') -and ($_ -notmatch '^api$') -and ($_ -notmatch '^crm$') }
      $path = ($segments -join '/')
      $urlPath = if ($path -eq '') { '/' } else { '/' + $path }
      if ($routes -notcontains $urlPath) { $routes += $urlPath }
    }
  }
  $lastmod = (Get-Date).ToString('yyyy-MM-dd')
  $urlsetOpen = '<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">'
  $urlsetClose = '</urlset>'
  $urls = $routes | ForEach-Object { '<url><loc>' + ($DOMAIN.TrimEnd('/') + $_) + '</loc><lastmod>' + $lastmod + '</lastmod></url>' }
  $xml = $urlsetOpen + ($urls -join '') + $urlsetClose
  Write-File 'public/sitemap.xml' $xml
}

# 7) Health check endpoint (static fallback for load balancers)
Invoke-Step 'Write /public/healthz.txt' { Write-File 'public/healthz.txt' ('ok ' + $STAMP) }

# 8) Sample reverse-proxy security headers (for Nginx/Apache) - saved as docs
Invoke-Step 'Emit security headers sample' {
  $headers = @'
# --- Suggested Reverse Proxy Headers ---
# Strict-Transport-Security (enable only after confirming TLS works site-wide)
add_header Strict-Transport-Security "max-age=63072000; includeSubDomains; preload" always;
add_header X-Content-Type-Options "nosniff" always;
add_header X-Frame-Options "DENY" always;
add_header Referrer-Policy "no-referrer-when-downgrade" always;
add_header Permissions-Policy "camera=(), microphone=(), geolocation=(self)" always;
# Content-Security-Policy: start conservative; extend if you load third-party assets
add_header Content-Security-Policy "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data: https:; font-src 'self' data:; connect-src 'self'; frame-ancestors 'none'; upgrade-insecure-requests" always;
'@;
  Write-File 'SITE_DOCUMENTS/security-headers-nginx.conf' $headers
}

# 9) Create deploy bundle (.zip)
Invoke-Step 'Create deployable zip' {
  $zipName = "dr-prod-bundle_${STAMP}.zip";
  if ($DRY) { Write-Host "DRY-RUN: zip -> $zipName (includes .next, public, package.json, package-lock.json, README_DEPLOY.md)" }
  else {
    $readme = @"
# Disaster Recovery – Production Bundle

This archive contains build artifacts ready to import into your hosting.

## Contents
- .next/               (build output)
- public/              (static assets, robots.txt, sitemap.xml, healthz.txt)
- package.json, package-lock.json

## Run (generic Node host)
1. Ensure Node 18+.
2. npm ci --omit=dev
3. npm run start (or your existing process manager)

If your host is static-only, you will need a Node-compatible host or adapter.
"@; Write-File 'README_DEPLOY.md' $readme
    if (Test-Path $zipName) { Remove-Item $zipName -Force }
    Add-Type -AssemblyName 'System.IO.Compression.FileSystem'
    [System.IO.Compression.ZipFile]::CreateFromDirectory((Resolve-Path '.').Path, (Resolve-Path '.').Path + "\$zipName")
    Write-Host "Created $zipName" -ForegroundColor Green
  }
}

# 10) Final summary
Invoke-Step 'Summary' {
  Write-Host 'Domain: ' $DOMAIN -ForegroundColor Green
  Write-Host 'robots.txt -> public/robots.txt' -ForegroundColor Green
  Write-Host 'sitemap.xml -> public/sitemap.xml (static routes only)' -ForegroundColor Green
  Write-Host 'healthz.txt -> public/healthz.txt' -ForegroundColor Green
  Write-Host 'Security headers sample -> SITE_DOCUMENTS/security-headers-nginx.conf' -ForegroundColor Green
  Write-Host 'Bundle zip created in repo root (disable DRY_RUN to produce real zip).'
}
